  "window_type" text,
  "qty" integer,
  "width_mm" integer,
  "height_mm" integer,
  -- Select: Left | Right | Up | Down | Fixed
  "opening_direction" text,
  -- Select: Aluminium | uPVC | Timber
  "frame_material" text,
  "frame_colour" text,
  -- Link -> Glass Spec
  "glass_type" text,
  "is_double_glazed" boolean NOT NULL DEFAULT true,
  "is_safety_glass" boolean NOT NULL DEFAULT false,
  "reveal_mm" integer,
  "handle_height_mm" integer,
  "flyscreen" boolean NOT NULL DEFAULT false,
  "notes" text,
  PRIMARY KEY ("name")
);
